settings.custom_liquid:
{%- assign rng_blog = blogs['jewellery-guide'] -%}
{%- assign rng_limit = 7 -%}

<style>
.rng-journal {
  background: #faf8f5;
  padding: 64px 0;
}
.rng-journal__inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
}

/* ── Header ── */
.rng-journal__header {
  display: flex;
  align-items: baseline;
  gap: 20px;
  padding-bottom: 40px;
  border-bottom: 1px solid #e2ddd8;
  margin-bottom: 56px;
}
.rng-journal__eyebrow {
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: #b8976a;
  white-space: nowrap;
}
.rng-journal__title {
  font-family: 'Cormorant Garamond', Georgia, serif;
  font-size: clamp(2.4rem, 4.5vw, 4rem);
  font-weight: 300;
  font-style: italic;
  line-height: 1;
  color: #1a1714;
  margin: 0;
}

/* ── Hero ── */
.rng-journal__hero {
  margin-bottom: 64px;
  background: #ffffff;
  overflow: hidden;
  display: grid;
  grid-template-columns: 1fr 1fr;
}
.rng-journal__hero--no-img {
  grid-template-columns: 1fr;
}
@media (max-width: 749px) {
  .rng-journal__hero {
    grid-template-columns: 1fr;
  }
}
.rng-journal__hero-img {
  overflow: hidden;
  aspect-ratio: 4 / 3;
  background: linear-gradient(135deg, #ede8e2, #ddd5c9);
}
.rng-journal__hero-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.75s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.rng-journal__hero:hover .rng-journal__hero-img img {
  transform: scale(1.04);
}
.rng-journal__hero-body {
  padding: 52px 56px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}
.rng-journal__hero--no-img .rng-journal__hero-body {
  padding: 64px 60px;
  max-width: 760px;
}
@media (max-width: 749px) {
  .rng-journal__hero-body {
    padding: 32px 24px;
  }
}
.rng-journal__tag {
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: #b8976a;
  margin-bottom: 18px;
  display: block;
  text-decoration: none;
}
.rng-journal__hero-heading {
  font-family: 'Cormorant Garamond', Georgia, serif;
  font-size: clamp(1.8rem, 2.8vw, 2.7rem);
  font-weight: 400;
  font-style: italic;
  line-height: 1.2;
  color: #1a1714;
  margin: 0 0 18px;
  text-decoration: none;
  display: block;
}
.rng-journal__excerpt {
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 14px;
  line-height: 1.78;
  color: #7a746e;
  margin: 0 0 24px;
}
.rng-journal__meta {
  display: flex;
  align-items: center;
  gap: 12px;
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 11px;
  letter-spacing: 0.06em;
  color: #7a746e;
  margin-bottom: 28px;
}
.rng-journal__meta-dot {
  width: 3px;
  height: 3px;
  border-radius: 50%;
  background: #b8976a;
  flex-shrink: 0;
  display: inline-block;
}
.rng-journal__cta {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: #1a1714;
  text-decoration: none;
  transition: gap 0.3s ease;
}
.rng-journal__hero:hover .rng-journal__cta {
  gap: 16px;
}

/* ── Divider ── */
.rng-journal__divider {
  display: flex;
  align-items: center;
  gap: 20px;
  margin-bottom: 40px;
}
.rng-journal__divider::before,
.rng-journal__divider::after {
  content: '';
  flex: 1;
  height: 1px;
  background: #e2ddd8;
}
.rng-journal__divider span {
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: #7a746e;
  white-space: nowrap;
}

/* ── Grid ── */
.rng-journal__grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 2px;
  margin-bottom: 56px;
}
@media (max-width: 599px) {
  .rng-journal__grid {
    grid-template-columns: 1fr;
  }
}
@media (min-width: 990px) {
  .rng-journal__grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

/* ── Card ── */
.rng-journal__card {
  background: #ffffff;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  position: relative;
  text-decoration: none;
  color: inherit;
  transition: box-shadow 0.3s ease;
}
.rng-journal__card:hover {
  box-shadow: 0 10px 48px rgba(26, 23, 20, 0.08);
  z-index: 1;
}
.rng-journal__card-img {
  overflow: hidden;
  aspect-ratio: 3 / 2;
  background: linear-gradient(135deg, #ede8e2, #ddd5c9);
  flex-shrink: 0;
}
.rng-journal__card-img img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}
.rng-journal__card:hover .rng-journal__card-img img {
  transform: scale(1.05);
}
.rng-journal__card-img-placeholder {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
}
.rng-journal__card-img-placeholder svg {
  opacity: 0.18;
}
.rng-journal__card-body {
  padding: 26px 26px 28px;
  display: flex;
  flex-direction: column;
  flex-grow: 1;
  border-top: 2px solid #faf8f5;
}
.rng-journal__card-heading {
  font-family: 'Cormorant Garamond', Georgia, serif;
  font-size: clamp(1.2rem, 1.8vw, 1.5rem);
  font-weight: 400;
  font-style: italic;
  line-height: 1.3;
  color: #1a1714;
  margin: 0 0 10px;
  transition: color 0.2s ease;
}
.rng-journal__card:hover .rng-journal__card-heading {
  color: #b8976a;
}
.rng-journal__card-excerpt {
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 13px;
  line-height: 1.7;
  color: #7a746e;
  margin: 0 0 18px;
  flex-grow: 1;
  display: -webkit-box;
  -webkit-line-clamp: 3;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.rng-journal__card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: 16px;
  border-top: 1px solid #e2ddd8;
  margin-top: auto;
}
.rng-journal__date {
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 10px;
  letter-spacing: 0.1em;
  color: #7a746e;
}
.rng-journal__arrow {
  width: 28px;
  height: 28px;
  border: 1px solid #e2ddd8;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  color: #1a1714;
  flex-shrink: 0;
  transition: background 0.25s, border-color 0.25s, color 0.25s;
  line-height: 1;
}
.rng-journal__card:hover .rng-journal__arrow {
  background: #b8976a;
  border-color: #b8976a;
  color: #fff;
}

/* ── View All ── */
.rng-journal__footer {
  text-align: center;
  padding-top: 40px;
  border-top: 1px solid #e2ddd8;
}
.rng-journal__view-all {
  display: inline-flex;
  align-items: center;
  gap: 12px;
  font-family: 'Jost', 'DM Sans', sans-serif;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: #1a1714;
  text-decoration: none;
  padding: 14px 40px;
  border: 1px solid #1a1714;
  transition: background 0.25s, color 0.25s;
}
.rng-journal__view-all:hover {
  background: #1a1714;
  color: #faf8f5;
}
</style>

<section class="rng-journal">
  <div class="rng-journal__inner">

    <!-- Header -->
    <div class="rng-journal__header">
      <span class="rng-journal__eyebrow">Stories &amp; Guides</span>
      <h2 class="rng-journal__title">The Journal</h2>
    </div>

    <!-- Hero: first article -->
    {%- for article in rng_blog.articles limit: 1 -%}
      {%- assign show_img = false -%}
      {%- if article.image -%}{%- assign show_img = true -%}{%- endif -%}

      <div class="rng-journal__hero{% unless show_img %} rng-journal__hero--no-img{% endunless %}">
        {%- if show_img -%}
          <a href="{{ article.url }}" class="rng-journal__hero-img">
            {%- assign h_img = article.image | image_url: width: 900 -%}
            <img src="{{ h_img }}" alt="{{ article.image.alt | escape }}" loading="eager" width="{{ article.image.width }}" height="{{ article.image.height }}">
          </a>
        {%- endif -%}

        <div class="rng-journal__hero-body">
          <span class="rng-journal__tag">
            {%- if article.tags.size > 0 -%}{{ article.tags.first }}{%- else -%}Featured{%- endif -%}
          </span>
          <a href="{{ article.url }}" class="rng-journal__hero-heading">{{ article.title | escape }}</a>
          {%- if article.excerpt.size > 0 -%}
            <p class="rng-journal__excerpt">{{ article.excerpt | strip_html | truncate: 220 }}</p>
          {%- endif -%}
          <div class="rng-journal__meta">
            <time datetime="{{ article.published_at | date: '%Y-%m-%d' }}">{{ article.published_at | date: '%B %d, %Y' }}</time>
            {%- if article.author -%}
              <span class="rng-journal__meta-dot"></span>
              <span>{{ article.author }}</span>
            {%- endif -%}
          </div>
          <a href="{{ article.url }}" class="rng-journal__cta">Read Article &rarr;</a>
        </div>
      </div>
    {%- endfor -%}

    <!-- Grid: remaining articles -->
    {%- assign grid_limit = rng_limit | minus: 1 -%}
    {%- assign article_count = rng_blog.articles_count | minus: 1 -%}

    {%- if article_count > 0 -%}
      <div class="rng-journal__divider"><span>More From The Journal</span></div>
      <div class="rng-journal__grid">
        {%- for article in rng_blog.articles offset: 1 limit: grid_limit -%}
          <a class="rng-journal__card" href="{{ article.url }}">

            <div class="rng-journal__card-img">
              {%- if article.image -%}
                {%- assign c_img = article.image | image_url: width: 600 -%}
                <img src="{{ c_img }}" alt="{{ article.image.alt | escape }}" loading="lazy" width="{{ article.image.width }}" height="{{ article.image.height }}">
              {%- else -%}
                <div class="rng-journal__card-img-placeholder">
                  <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="#1a1714" stroke-width="1">
                    <rect x="3" y="3" width="18" height="18" rx="2"/>
                    <circle cx="8.5" cy="8.5" r="1.5"/>
                    <polyline points="21 15 16 10 5 21"/>
                  </svg>
                </div>
              {%- endif -%}
            </div>

            <div class="rng-journal__card-body">
              <span class="rng-journal__tag">
                {%- if article.tags.size > 0 -%}{{ article.tags.first }}{%- else -%}Journal{%- endif -%}
              </span>
              <h3 class="rng-journal__card-heading">{{ article.title | escape }}</h3>
              {%- if article.excerpt.size > 0 -%}
                <p class="rng-journal__card-excerpt">{{ article.excerpt | strip_html | truncate: 140 }}</p>
              {%- endif -%}
              <div class="rng-journal__card-footer">
                <time class="rng-journal__date" datetime="{{ article.published_at | date: '%Y-%m-%d' }}">
                  {{ article.published_at | date: '%b %d, %Y' }}
                </time>
                <span class="rng-journal__arrow">&rarr;</span>
              </div>
            </div>

          </a>
        {%- endfor -%}
      </div>
    {%- endif -%}

    <!-- View All -->
    {%- if rng_blog.articles_count > rng_limit -%}
      <div class="rng-journal__footer">
        <a class="rng-journal__view-all" href="{{ rng_blog.url }}">View All Articles</a>
      </div>
    {%- endif -%}

  </div>
</section>
